const s=()=>Math.random().toString(36).slice(2),m=r=>new Intl.NumberFormat("en-IN",{minimumFractionDigits:2,maximumFractionDigits:2}).format(r),o=r=>{if(!r)return"-";const t=r.trim();if(/^\d{8}$/.test(t))return`${t.slice(6,8)}/${t.slice(4,6)}/${t.slice(0,4)}`;if(/^\d{4}-\d{2}-\d{2}$/.test(t)){const[n,e,i]=t.split("-");return`${i}/${e}/${n}`}return/^\d{2}\/\d{2}\/\d{4}$/.test(t),t},a=r=>{const t=r.getFullYear(),n=String(r.getMonth()+1).padStart(2,"0"),e=String(r.getDate()).padStart(2,"0");return`${t}${n}${e}`};export{o as a,m as f,s as m,a as t};
